#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int countElementsSmallerThanMid(int row[], int rowSize, int midValue) {
    int lowIndex = 0, highIndex = rowSize - 1;
    while (lowIndex <= highIndex) {
        int middleIndex = (lowIndex + highIndex) / 2;
        if (row[middleIndex] <= midValue) {
            lowIndex = middleIndex + 1;
        } else {
            highIndex = middleIndex - 1;
        }
    }
    return lowIndex;
}

int findMedianValue(int** matrix, int rowCount, int columnCount) {
    int lowValue = INT_MAX;
    int highValue = INT_MIN;

    for (int i = 0; i < rowCount; i++) {
        for (int j = 0; j < columnCount; j++) {
            lowValue = (matrix[i][j] < lowValue) ? matrix[i][j] : lowValue;
            highValue = (matrix[i][j] > highValue) ? matrix[i][j] : highValue;
        }
    }

    while (lowValue <= highValue) {
        int midValue = (lowValue + highValue) / 2;
        int count = 0;
        for (int i = 0; i < rowCount; i++) {
            count += countElementsSmallerThanMid(matrix[i], columnCount, midValue);
        }
        if (count <= (rowCount * columnCount) / 2) {
            lowValue = midValue + 1;
        } else {
            highValue = midValue - 1;
        }
    }
    return lowValue;
}

