function countElementsSmallerThanMid(row, midValue) {
    let lowIndex = 0, highIndex = row.length - 1;
    while (lowIndex <= highIndex) {
        const middleIndex = Math.floor((lowIndex + highIndex) / 2);
        if (row[middleIndex] <= midValue) {
            lowIndex = middleIndex + 1;
        } else {
            highIndex = middleIndex - 1;
        }
    }
    return lowIndex;
}

function findMedianValue(matrix) {
    let lowValue = Infinity;
    let highValue = -Infinity;
    const rowCount = matrix.length;
    const columnCount = matrix[0].length;

    // Find the minimum and maximum values in the matrix
    for (let i = 0; i < rowCount; i++) {
        for (let j = 0; j < columnCount; j++) {
            lowValue = Math.min(lowValue, matrix[i][j]);
            highValue = Math.max(highValue, matrix[i][j]);
        }
    }

    // Binary search for the median
    while (lowValue <= highValue) {
        const midValue = Math.floor((lowValue + highValue) / 2);
        let count = 0;
        for (let i = 0; i < rowCount; i++) {
            count += countElementsSmallerThanMid(matrix[i], midValue);
        }
        if (count <= (rowCount * columnCount) / 2) {
            lowValue = midValue + 1;
        } else {
            highValue = midValue - 1;
        }
    }
    return lowValue;
}

